const express = require('express');
const app = express();
const bodyParser = require('body-parser');
const crypto = require('crypto');

app.use(bodyParser.json());

const SECRET_KEY = 'your_secret_key_here';

const levels = {
  1: { reward: 100 },
  2: { reward: 200 },
  3: { reward: 300 }
};

let userProgress = {};

function verifyRequest(req, res, next) {
  const signature = req.headers['x-signature'];
  const hash = crypto.createHmac('sha256', SECRET_KEY)
                     .update(JSON.stringify(req.body))
                     .digest('hex');
  if (signature !== hash) {
    return res.status(403).send('Invalid request signature');
  }
  next();
}

app.post('/complete-level', verifyRequest, (req, res) => {
  const { userId, levelId, score, time } = req.body;

  if (!levels[levelId]) {
    return res.status(400).send('Invalid level');
  }

  if (!userProgress[userId]) {
    userProgress[userId] = { completedLevels: [] };
  }

  if (userProgress[userId].completedLevels.includes(levelId)) {
    return res.status(400).send('Level already completed');
  }

  userProgress[userId].completedLevels.push(levelId);
  res.status(200).send('Level completed');
});

app.post('/claim-reward', verifyRequest, (req, res) => {
  const { userId, levelId } = req.body;

  if (!levels[levelId]) {
    return res.status(400).send('Invalid level');
  }

  if (!userProgress[userId] || !userProgress[userId].completedLevels.includes(levelId)) {
    return res.status(400).send('Level not completed');
  }

  const reward = levels[levelId].reward;
  res.status(200).send({ reward });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});